#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int K;
    scanf("%d", &K);
    for (int i = 0; i < K; i++) {
        int a, b, l, r;
        scanf("%d %d %d %d", &a, &b, &l, &r);
        int max_gcd = 0;
        for (int p = a; p <= b; p++) {
            for (int q = l; q <= r; q++) {
                max_gcd = (gcd(p, q) > max_gcd) ? gcd(p, q) : max_gcd;
            }
        }
        printf("%d\n", max_gcd);
    }
    return 0;
}

