import java.util.Scanner;

public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int K = sc.nextInt();
        for (int i = 0; i < K; i++) {
            int a = sc.nextInt();
            int b = sc.nextInt();
            int l = sc.nextInt();
            int r = sc.nextInt();
            int max_gcd = 0;
            for (int p = a; p <= b; p++) {
                for (int q = l; q <= r; q++) {
                    max_gcd = (gcd(p, q) > max_gcd) ? gcd(p, q) : max_gcd;
                }
            }
            System.out.println(max_gcd);
        }
    }
}

