import math

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

K = int(input())
for _ in range(K):
    a, b, l, r = map(int, input().split())
    max_gcd = 0
    for p in range(a, b + 1):
        for q in range(l, r + 1):
